        // Convert mouse position from screen space to world space
        Vector3 mouseWorldPosition = cam.ScreenToWorldPoint(new Vector3(mouseScreenPosition.x, mouseScreenPosition.y, cam.nearClipPlane));

        // Now, we need to convert the Rect, which is in 2D space, to work with our 3D world space
        // We'll do this by taking only the x and y components since we assume the rect exists on a plane in world space
        Vector2 mouseWorldPosition2D = new Vector2(mouseWorldPosition.x, mouseWorldPosition.y);

        // Check if the 2D mouse position in world space is within the bounds of the worldRect
        if (worldRect.Contains(mouseWorldPosition2D))
        {
